'use client';

import { useEffect } from 'react';

export default function SpringCursor() {
  useEffect(() => {
    if (typeof window === 'undefined') return;

    const el = document.createElement('div');
    el.id = 'ryyan-custom-cursor';
    el.style.cssText = 'position:fixed;top:0;left:0;pointer-events:none;z-index:9999;will-change:transform;transform-origin:0 0;display:none;';
    el.innerHTML = `<svg width="24" height="32" viewBox="0 0 24 32" overflow="visible" fill="none">
      <defs>
        <filter id="cur-mb" x="-150%" y="-150%" width="400%" height="400%">
          <feGaussianBlur id="cur-blur" stdDeviation="0 0" in="SourceGraphic" result="blur"/>
          <feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>
        </filter>
      </defs>
      <g filter="url(#cur-mb)">
        <path d="M2 2 L2 26 L7.5 20.5 L12.5 29 L15.2 27.5 L10.2 19 L18 19 Z" fill="rgba(0,0,0,0.45)" transform="translate(1.5,1.5)"/>
        <path d="M2 2 L2 26 L7.5 20.5 L12.5 29 L15.2 27.5 L10.2 19 L18 19 Z" fill="white"/>
      </g>
    </svg>`;
    document.body.appendChild(el);

    const style = document.createElement('style');
    style.id = 'ryyan-cursor-style';
    style.textContent = '@media(hover:hover)and(pointer:fine){body,body *{cursor:none!important}}';
    document.head.appendChild(style);

    let mx = 0, my = 0, x = 0, y = 0, vx = 0, vy = 0;
    let sc = 1, st = 1, sv = 0, lt = performance.now();
    const PS = 240, PD = 27, SS = 330, SD = 30;

    const onMove = (e) => {
      el.style.display = 'block';
      mx = e.clientX;
      my = e.clientY;
    };
    const onDown = () => (st = 0.65);
    const onUp = () => (st = 1);

    window.addEventListener('mousemove', onMove);
    window.addEventListener('mousedown', onDown);
    window.addEventListener('mouseup', onUp);

    const tick = () => {
      const now = performance.now(), dt = Math.min((now - lt) / 1000, 0.033); lt = now;
      vx += ((mx - x) * PS - vx * PD) * dt;
      vy += ((my - y) * PS - vy * PD) * dt;
      x += vx * dt;
      y += vy * dt;
      sv += ((st - sc) * SS - sv * SD) * dt;
      sc += sv * dt;
      el.style.transform = `translate(${x}px,${y}px) scale(${sc})`;

      const speed = Math.sqrt(vx * vx + vy * vy);
      const blurEl = el.querySelector('#cur-blur');
      if (blurEl) {
        if (speed > 20) {
          const a = Math.atan2(vy, vx), amt = Math.min(speed * 0.005, 2.8);
          blurEl.setAttribute('stdDeviation', `${(Math.abs(Math.cos(a)) * amt).toFixed(2)} ${(Math.abs(Math.sin(a)) * amt).toFixed(2)}`);
        } else blurEl.setAttribute('stdDeviation', '0 0');
      }
      requestAnimationFrame(tick);
    };

    const anim = requestAnimationFrame(tick);

    return () => {
      cancelAnimationFrame(anim);
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mousedown', onDown);
      window.removeEventListener('mouseup', onUp);
      document.body.removeChild(el);
      document.head.removeChild(style);
    };
  }, []);

  return null;
}
